functions.body:
case "${1:-}" in
1|true|TRUE|True|yes|YES|Yes) return 0 ;;
*) return 1 ;;
esac

local f="$1"
if [ ! -e "$f" ]; then printf '0'; return 0; fi
case "$(uname 2>/dev/null || echo Linux)" in
Darwin) stat -f %m "$f" 2>/dev/null || printf '0' ;;
*) stat -c %Y "$f" 2>/dev/null || printf '0' ;;
esac
